import{_ as a,o as i,c as r,a0 as t}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"Administer OCR Providers","description":"","frontmatter":{},"headers":[],"relativePath":"admin/ocr-settings.md","filePath":"admin/ocr-settings.md"}'),n={name:"admin/ocr-settings.md"};function o(s,e,l,c,d,h){return i(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="administer-ocr-providers" tabindex="-1">Administer OCR Providers <a class="header-anchor" href="#administer-ocr-providers" aria-label="Permalink to &quot;Administer OCR Providers&quot;">​</a></h1><p>The <strong>Image Processing Settings</strong> area controls which screenshot-processing options users can see and use.</p><blockquote><p>Screenshot placeholder: ocr-admin.png</p></blockquote><h2 id="what-this-admin-facing-area-includes" tabindex="-1">What this admin-facing area includes <a class="header-anchor" href="#what-this-admin-facing-area-includes" aria-label="Permalink to &quot;What this admin-facing area includes&quot;">​</a></h2><p>The current interface really does include:</p><ul><li>provider enable or disable controls</li><li>a recommended-provider setting</li><li>a warning-message setting for Free Local Processing</li><li>diagnostics for local OCR and Gemini status</li><li>a local OCR test action</li></ul><p>This admin-facing control surface appears to be recently added compared with older planning notes, but it is present in the current interface.</p><h2 id="provider-controls" tabindex="-1">Provider controls <a class="header-anchor" href="#provider-controls" aria-label="Permalink to &quot;Provider controls&quot;">​</a></h2><p>Authorized admins can manage:</p><ul><li><strong>Enable Free Local Processing</strong></li><li><strong>Enable Gemini</strong></li><li><strong>Enable Premium Processing placeholder</strong></li><li>the recommended provider users see first</li></ul><p>Premium Processing is still only a placeholder today.</p><h2 id="warning-text" tabindex="-1">Warning text <a class="header-anchor" href="#warning-text" aria-label="Permalink to &quot;Warning text&quot;">​</a></h2><p>Admins can also control whether a warning appears on imports when users choose Free Local Processing, and they can edit the text of that warning.</p><h2 id="diagnostics-panel" tabindex="-1">Diagnostics panel <a class="header-anchor" href="#diagnostics-panel" aria-label="Permalink to &quot;Diagnostics panel&quot;">​</a></h2><p>The diagnostics panel can show things like:</p><ul><li>whether local OCR is available</li><li>Tesseract version and language support</li><li>image preprocessing availability</li><li>whether Gemini is configured</li><li>default provider</li><li>the last run or last error</li></ul><p>It also includes a <strong>Test Local OCR</strong> action.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>leave Free Local enabled unless you have a strong reason not to</li><li>recommend Gemini when users regularly handle difficult screenshots</li><li>do not describe Premium Processing as live yet</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../imports/choose-provider.html">Choose an Image-Processing Provider</a></li><li><a href="./../imports/gemini-key.html">Set Up Your Gemini API Key</a></li></ul>',21)])])}const m=a(n,[["render",o]]);export{g as __pageData,m as default};
